arguments.argument:
if global.gamePaused=false
{
  timeToHit+=1
  if timeToHit=damageTimeThres
  {
    if oPlayer1.y<256 {y=16}
    else {y=256}
    timeToHit=1000
  }
  else if timeToHit>=1001 and timeToHit<=1065
  {
    image_alpha+=0.01
  }
  else if timeToHit=1066
  {
    bCanDealDamage=1
    image_alpha=1
  }
  else if timeToHit=1068
  {
    bCanDealDamage=0
    image_alpha=0
    timeToHit=0
  }
}
